```class Solution {
public:
    int findMaxK(vector<int>& nums) {
        unordered_set<int> s(nums.begin(), nums.end());
        int res = -1;
        for (int num : nums) {
            if (s.count(-num)) {
                res = max(res, abs(num));
            }
        }
        return res;
    }
};
